const uuid = $('Webhook').first().json.body.uuid;
const uuid_old = $('Webhook').first().json.body.uuid_old;

// 使用正则替换所有换行符（\n、\r）为空字符串
const cleanUuid = uuid.replace(/\s|\/n/g, '');


// 返回清理后的数据
return {
  json: {
    body: {
      uuid: cleanUuid
    }
  }
};

let inputArray = $input.all();
let result = null;

// Check if input is a non-empty array
if (Array.isArray(inputArray) && inputArray.length > 0) {
    let firstItem = inputArray[0];

    if (firstItem?.json?.body) {
        let body = firstItem.json.body;

        if (body.uuid) {
            let uuid = body.uuid.trim();

            // Process based on UUID format
            if (uuid.length === 30) {
                // Handle 30-character UUID format
                body.uuid = uuid;
                // Remove characters at positions 16-17 (17th and 18th characters)
                body.uuid_unique = body.uuid.slice(0, 16) + body.uuid.slice(18);
            } else {
                // Handle URL format
                const regex = /a=[\w\s]+?([A-Fa-f\d]+)&b=([A-Fa-f\d]+)&c=([A-Fa-f\d]+)/;
                const match = uuid.match(regex);

                if (match && match.length === 4) {
                    const parts = [match[1], match[2], match[3]].map(s => s);
                    body.uuid = parts.join('');
                    body.uuid_unique = body.uuid.slice(0, 16) + body.uuid.slice(18);
                }
            }

            result = body;
            console.log("Processed UUID:", { uuidId: body.uuid, uuid_unique: body.uuid_unique });


        } else {
            console.log("UUID not found in body.");
        }
    } else {
        console.log("Body not found in first item.");
    }
} else {
    console.log("Input array is empty or not an array.");
}

return result;

